SELECT m.region_no, r.region_name, m.member_no, c.charge_amt FROM charge AS c JOIN member AS m ON c.member_no = m.member_no JOIN region AS r ON m.region_no = r.region_no JOIN payment AS p ON m.member_no = p.member_no WHERE (r.region_name IN ('China', 'Africa')) AND (strftime('%Y', p.payment_dt) = '2000' OR strftime('%Y', p.payment_dt) = '1999')
